<?php
require_once 'config.php';require_auth();ensure_schema();$pageTitle='Órdenes de trabajo';$pdo=db();$q=clean_text($_GET['q']??'');$status=clean_text($_GET['status']??'');$page=max(1,(int)($_GET['page']??1));$per=20;$offset=($page-1)*$per;$where=[];$params=[];
if($q!==''){$where[]='(wo.code LIKE ? OR c.name LIKE ? OR c.phone LIKE ? OR v.plate LIKE ? OR v.engine_number LIKE ? OR v.chassis_number LIKE ?)';$like="%$q%";array_push($params,$like,$like,$like,$like,$like,$like);}if($status!==''&&in_array($status,STATUSES,true)){$where[]='wo.current_status=?';$params[]=$status;}$ws=$where?'WHERE '.implode(' AND ',$where):'';
$st=$pdo->prepare("SELECT COUNT(*) FROM work_orders wo JOIN clients c ON c.id=wo.client_id JOIN vehicles v ON v.id=wo.vehicle_id $ws");$st->execute($params);$total=(int)$st->fetchColumn();$pages=max(1,(int)ceil($total/$per));$st=$pdo->prepare("SELECT wo.*,c.name client_name,c.phone,v.brand,v.model,v.plate FROM work_orders wo JOIN clients c ON c.id=wo.client_id JOIN vehicles v ON v.id=wo.vehicle_id $ws ORDER BY wo.updated_at DESC LIMIT $per OFFSET $offset");$st->execute($params);$rows=$st->fetchAll();include 'partials/header.php';?>
<div class="page-head"><div class="page-head-copy"><h1>Órdenes de trabajo</h1><p>Buscá por cliente, patente, motor, chasis o código.</p></div><div class="actions"><a class="btn btn-primary" href="order_new.php">Nueva orden</a></div></div>
<section class="card"><form class="toolbar" method="get"><div class="search"><input name="q" value="<?=h($q)?>" placeholder="Buscar orden, cliente, patente, motor o chasis"></div><select name="status"><option value="">Todos los estados</option><?php foreach(STATUSES as $s):?><option value="<?=h($s)?>" <?=$status===$s?'selected':''?>><?=h($s)?></option><?php endforeach;?></select><button class="btn">Filtrar</button><?php if($q!==''||$status!==''):?><a class="btn btn-ghost" href="orders.php">Limpiar</a><?php endif;?></form><div class="card-header"><div><h2><?=$total?> resultado<?=$total===1?'':'s'?></h2><p>Página <?=$page?> de <?=$pages?></p></div></div>
<?php if($rows):?><div class="table-wrap responsive"><table><thead><tr><th>Orden</th><th>Cliente</th><th>Moto</th><th>Estado</th><th>Prioridad</th><th>Actualizada</th><th></th></tr></thead><tbody><?php foreach($rows as $r):?><tr><td class="primary-cell"><strong><?=h($r['code'])?></strong><br><small class="muted">Creada <?=h(date_ar($r['created_at']))?></small></td><td data-label="Cliente"><strong><?=h($r['client_name'])?></strong><br><small class="muted"><?=h($r['phone'])?></small></td><td data-label="Moto"><strong><?=h($r['brand'].' '.$r['model'])?></strong><br><small class="muted"><?=h($r['plate'])?></small></td><td data-label="Estado"><span class="status <?=h(status_tone($r['current_status']))?>"><?=h($r['current_status'])?></span></td><td data-label="Prioridad"><span class="badge <?=h(priority_tone($r['priority']))?>"><?=h(ucfirst($r['priority']))?></span></td><td data-label="Actualizada"><?=h(date_ar($r['updated_at'],true))?></td><td data-label="Acción"><a class="btn btn-sm" href="order_view.php?id=<?=(int)$r['id']?>">Abrir</a></td></tr><?php endforeach;?></tbody></table></div><?php else:?><div class="empty-state"><div><div class="empty-icon">⌕</div><h2>No encontramos órdenes</h2><p class="muted">Probá otra búsqueda.</p></div></div><?php endif;?>
<?php if($pages>1):?><div class="form-actions"><?php if($page>1):?><a class="btn" href="?q=<?=urlencode($q)?>&status=<?=urlencode($status)?>&page=<?=$page-1?>">Anterior</a><?php endif;?><?php if($page<$pages):?><a class="btn" href="?q=<?=urlencode($q)?>&status=<?=urlencode($status)?>&page=<?=$page+1?>">Siguiente</a><?php endif;?></div><?php endif;?></section><?php include 'partials/footer.php';?>
